import React, { useEffect } from "react";
import "./Header.scss";

// import Logo from "../images/Logo.png";
import { Link, useNavigate } from "react-router-dom";
import Logo from "../images/Logo_Backup.png";

import { motion } from "framer-motion";

const Header = () => {
  const navigate = useNavigate();

  useEffect(() => {
    setTimeout(() => {
      let lastPage = window.localStorage.getItem("last-page");

      if (lastPage) {
        navigate(lastPage);
      }
    }, 800);
  });

  return (
    <header>
      <motion.div
        initial={{ opacity: 0, scale: 0.5 }} // Start animation
        animate={{ opacity: 1, scale: 1 }} // End animation
        transition={{ duration: 0.5 }} // Animation duration
        style={{
          width: 100,
          height: 100,
          background: "blue",
          borderRadius: 10,
          margin: "20px auto",
        }}
      />

      <div
        className="logo"
        onClick={() => {
          window.localStorage.setItem("last-page", "/");

          navigate("/");
        }}
      >
        <img src={Logo} alt="CodeFellow" />
        <h2>
          <span>Code</span>Fellow
        </h2>
      </div>

      <ul>
        <li>
          <Link to="/learn">Technologies</Link>
        </li>
        <li>
          <Link to="/roadmap">Roadmaps</Link>
        </li>
      </ul>
    </header>
  );
};

export default Header;
